const event = $input.first().json;
const data = event.data || event;

const threatTypes = {
  'user.session.hijack': 'session-hijack',
  'user.account.report_suspicious_activity': 'user-reported-suspicious',
  'security.threat.detected': 'okta-threatinsight',
  'policy.evaluate_sign_on': 'anomalous-login',
  'user.authentication.auth_via_mfa': 'mfa-anomaly'
};

const eventType = data.eventType || 'unknown';
const threatCategory = Object.entries(threatTypes).find(([k]) => eventType.includes(k))?.[1] || 'credential-anomaly';

const actor = data.actor || {};
const client = data.client || {};
const target = (data.target || [])[0] || {};

return [{
  json: {
    incidentId: 'CRED-' + Date.now().toString(36).toUpperCase(),
    threatCategory,
    eventType,
    userId: target.id || actor.id,
    userLogin: target.alternateId || actor.alternateId,
    userDisplayName: target.displayName || actor.displayName,
    sourceIp: client.ipAddress,
    userAgent: client.userAgent?.rawUserAgent || 'unknown',
    geolocation: client.geographicalContext?.city + ', ' + (client.geographicalContext?.country || ''),
    sessionId: data.authenticationContext?.externalSessionId,
    timestamp: data.published || new Date().toISOString(),
    severity: ['session-hijack', 'user-reported-suspicious'].includes(threatCategory) ? 'SEV1' : 'SEV2'
  }
}];

